3	import (
4		"encoding/json"
5		"fmt"
6		"log"
7		"os"
8	
9		amqp "github.com/rabbitmq/amqp091-go"
10	
11		"notification-service/internal/handlers"
12	)
13	
14	const (
15		exchangeName = "notifications"
16		queueName    = "notification-service.email"
17		routingKey   = "email.*"
18		prefetchCount = 10
19	)
20	
21	type emailMessage struct {
22		EventType string          `json:"event_type"`
23		Timestamp string          `json:"timestamp"`
24		Payload   json.RawMessage `json:"payload"`
25	}
26	
27	func Start() error {
28		conn, err := connect()
29		if err != nil {
30			return err
31		}
32	
33		conn.NotifyClose(make(chan *amqp.Error, 1))
34	
35		ch, err := conn.Channel()
36		if err != nil {
37			return fmt.Errorf("open channel: %w", err)
38		}
39	
40		if err := ch.Qos(prefetchCount, 0, false); err != nil {
41			return fmt.Errorf("set prefetch: %w", err)
42		}
43	
44		if err := ch.ExchangeDeclare(exchangeName, "topic", true, false, false, false, nil); err != nil {
45			return fmt.Errorf("declare exchange: %w", err)
46		}
47	
48		if _, err := ch.QueueDeclare(queueName, true, false, false, false, nil); err != nil {
49			return fmt.Errorf("declare queue: %w", err)
50		}
51	
52		if err := ch.QueueBind(queueName, routingKey, exchangeName, false, nil); err != nil {
53			return fmt.Errorf("bind queue: %w", err)
54		}
55	
56		msgs, err := ch.Consume(queueName, "", false, false, false, false, nil)
57		if err != nil {
58			return fmt.Errorf("start consume: %w", err)
59		}
60	
61		log.Printf("[consumer] Listening on queue %q (routing: %s)", queueName, routingKey)
62	
63		connErrors := make(chan *amqp.Error, 1)
64		conn.NotifyClose(connErrors)
65	
66		go func() {
67			for msg := range msgs {
68				processMessage(ch, msg)
69			}
70		}()
71	
72		if err := <-connErrors; err != nil {
73			log.Printf("[consumer] Connection closed: %v", err)
74			os.Exit(1)
75		}
76	
77		return nil
78	}
79	
80	func connect() (*amqp.Connection, error) {
81		host := getenv("RABBITMQ_HOST", "rabbitmq")
82		port := getenv("RABBITMQ_PORT", "5672")
83		user := getenv("RABBITMQ_USER", "guest")
84		pass := getenv("RABBITMQ_PASSWORD", "guest")
85		vhost := getenv("RABBITMQ_VHOST", "/")
86	
87		url := fmt.Sprintf("amqp://%s:%s@%s:%s/%s", user, pass, host, port, vhost)
88		log.Printf("[consumer] Connecting to RabbitMQ at %s:%s...", host, port)
89		return amqp.Dial(url)
90	}
91	
92	func processMessage(ch *amqp.Channel, msg amqp.Delivery) {
93		var m emailMessage
94		if err := json.Unmarshal(msg.Body, &m); err != nil {
95			log.Printf("[consumer] Failed to parse message: %v", err)
96			_ = msg.Nack(false, false)
97			return
98		}
99	
100		log.Printf("[consumer] Received %s", m.EventType)
101	
102		if err := dispatch(m); err != nil {
103			log.Printf("[consumer] Failed to process %s: %v", m.EventType, err)
104			_ = msg.Nack(false, false)
105			return
106		}
107	
108		_ = msg.Ack(false)
109	}
110	
111	func dispatch(m emailMessage) error {
112		switch m.EventType {
113		case "email.password_reset":
114			var payload handlers.PasswordResetPayload
115			if err := json.Unmarshal(m.Payload, &payload); err != nil {
116				return fmt.Errorf("unmarshal payload: %w", err)
117			}
118			return handlers.HandlePasswordReset(payload)
119		default:
120			log.Printf("[consumer] Unhandled event_type: %s", m.EventType)
121			return nil
122		}
123	}
124	
125	func getenv(key, fallback string) string {
126		if v := os.Getenv(key); v != "" {
127			return v
128		}
129		return fallback
130	}
